/**
 * @suppress
 */
public object FfiConverterTypeSshSession: FfiConverter<SshSession, Long> {
    override fun lower(value: SshSession): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): SshSession {
        return SshSession(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): SshSession {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: SshSession) = 8UL

    override fun write(value: SshSession, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



