    {
        

        companion object
    }
    
    data class InProgress(
        val `transferId`: kotlin.String, 
        val `mode`: kotlin.String, 
        val `fileName`: kotlin.String?, 
        val `transferred`: kotlin.ULong, 
        val `total`: kotlin.ULong?) : TrzszPublicState()
        
    {
        

        companion object
    }
    
    data class Done(
        val `transferId`: kotlin.String, 
        val `success`: kotlin.Boolean, 
